    throw new TypeError(
      `deepMerge: 'target' must be a plain object (received ${target === null ? "null" : typeof target})`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object (received ${source === null ? "null" : typeof source})`
    );
  }

  return mergeInto(target, source, new WeakMap());
