const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function deepMergeInto(
  target: PlainObject,
  source: PlainObject,
  seen: WeakMap<PlainObject, PlainObject>
): PlainObject {
  if (seen.has(source)) {
    return seen.get(source)!;
  }

  seen.set(source, target);

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) continue;

    const sourceVal = source[key];

    if (sourceVal === undefined) continue;

    if (!Object.prototype.hasOwnProperty.call(target, key)) {
      target[key] = deepClone(sourceVal, seen);
      continue;
    }

    const targetVal = target[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      target[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      target[key] = deepMergeInto({ ...targetVal }, sourceVal, seen);
    } else {
      target[key] = deepClone(sourceVal, seen);
    }
  }

  return target;
}

function deepClone(value: unknown, seen: WeakMap<PlainObject, PlainObject>): unknown {
  if (value === null || typeof value !== "object") return value;
  if (Array.isArray(value)) return value.map((item) => deepClone(item, seen));
  if (isPlainObject(value)) {
    const cloned: PlainObject = {};
    seen.set(value, cloned);
    for (const key of Object.keys(value)) {
      if (UNSAFE_KEYS.has(key)) continue;
      cloned[key] = deepClone(value[key], seen);
    }
    return cloned;
  }
  // Non-plain objects (Date, RegExp, Map, Set, etc.) — return as-is (reference copy)
  return value;
}

